async (page) => {
  var title = "图解 Blaze · 第 10 章 · 分页 — 图解 Blaze-Persistence";
  var html = "<section style=\"margin-bottom:24px;\">\n<h2 style=\"font-size:24px;font-weight:800;color:#1a1a2e;line-height:1.4;margin:0 0 8px;\">第 10 章 · 分页</h2>\n</section>\n<section><p style=\"font-size:14px;color:#888;margin-bottom:28px;line-height:1.7;\">Offset 分页 · Keyset 分页 · COUNT 优化 · PagedList · Entity View 分页</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #1e6fff22;border-radius:10px;padding:20px 22px 14px;margin:0 0 28px;line-height:1.9;\"><p style=\"font-size:15px;color:#2b2b2b;margin-bottom:10px;line-height:1.8;\">\n    分页是几乎每个后端系统都要面对的基本问题，然而传统的 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">OFFSET / LIMIT</code> 方案在数据量增长后性能急剧恶化，\n    并且在并发写入场景下会产生\"丢行/重复行\"的一致性缺陷。Blaze-Persistence 提供了基于 <strong style=\"color:#1a1a2e;font-weight:700;\">Keyset 分页</strong>\n    的 O(1) 方案，同时保留了传统 Offset 分页的 API 兼容性，并可无缝结合 Entity View 投影。\n  </p><ul style=\"margin:8px 0 8px 20px;color:#2b2b2b;\"><li style=\"margin-bottom:4px;font-size:13px;\">理解 Offset 分页的 O(n) 复杂度根因</li><li style=\"margin-bottom:4px;font-size:13px;\">掌握 Keyset 分页的数学原理与 SQL 模式</li><li style=\"margin-bottom:4px;font-size:13px;\">使用 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">PaginatedCriteriaBuilder</code> 构建高效分页查询</li><li style=\"margin-bottom:4px;font-size:13px;\">优化 COUNT 查询与 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">withExtractAllKeysets</code> 预计算</li><li style=\"margin-bottom:4px;font-size:13px;\">将 Entity View 与分页 API 无缝结合</li><li style=\"margin-bottom:4px;font-size:13px;\">处理多列 Keyset 与 NULL 排序</li><li style=\"margin-bottom:4px;font-size:13px;\">识别 Keyset 分页的限制场景</li></ul><p style=\"font-size:12px;color:#888;margin-top:10px;padding-top:10px;border-top:1px solid #e5e7eb;\">前置知识：<span style=\"color:#1e6fff;\">第 3 章 · CriteriaBuilder 查询引擎</span></p></section>\n<section><h2 style=\"font-size:20px;font-weight:700;color:#1a1a2e;border-bottom:2px solid #1e6fff;padding-bottom:6px;margin:36px 0 16px;\">10.1 Offset 分页的问题</h2></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">传统分页依赖 SQL 的 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">OFFSET n LIMIT m</code> 语法。数据库引擎必须先扫描并跳过前 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">n</code> 行，\n才能返回目标页的 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">m</code> 行。当 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">n</code> 增大时，跳过的行数线性增长，导致查询时间随页码线性上升。</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">Offset 分页的行扫描模型 — 越往后越慢</p><p style=\"font-size:13px;color:#2b2b2b;line-height:2;margin:8px 0;\">\n\n第 1 页 · OFFSET 0\n✅ 返回 20 行\n\n\n第 50 页 · OFFSET 980\n⏭ 跳过 980 行 → ✅ 返回 20 行\n\n\n第 500 页 · OFFSET 9980\n⏭ 跳过 9,980 行 → ✅ 返回 20 行\n\n\n第 5000 页 · OFFSET 99,980\n⏭ 跳过 99,980 行 → ✅ 返回 20 行\n\n</p></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">除了性能问题，Offset 分页在并发写入场景下还存在<strong style=\"color:#1a1a2e;font-weight:700;\">一致性缺陷</strong>：</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">并发修改导致的丢行与重复行</p><table style=\"width:100%;border-collapse:collapse;margin:0 0 8px;\"><tr><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">用户浏览器</th><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">数据库</th></tr></table><p style=\"text-align:center;font-size:11px;color:#888;background:#f5f5f5;border:1px solid #e6a81744;border-radius:4px;padding:4px 8px;margin:3px auto;max-width:80%;\">📌 另一用户在 B 前面插入了新行 X</p><p style=\"text-align:center;font-size:11px;color:#888;background:#f5f5f5;border:1px solid #e6a81744;border-radius:4px;padding:4px 8px;margin:3px auto;max-width:80%;\">📌 C 出现两次！因为插入 X 后行整体后移[BR]第 2 页本应是 [D, E, F]</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e0525244;border-radius:8px;padding:14px 16px;margin:14px 0 20px;font-size:14px;line-height:1.8;color:#2b2b2b;\">\n<strong style=\"color:#1a1a2e;font-weight:700;\">⚠ 生产事故场景：</strong>在高写入频率的订单系统中，运营人员翻页导出数据时，\n  Offset 分页可能导致部分订单漏掉或重复导出，引发资金对账异常。\n</section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">性能退化的根本原因是 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">OFFSET</code> 迫使数据库做 <strong style=\"color:#1a1a2e;font-weight:700;\">O(n)</strong> 的行扫描：</p></section>\n<section><table style=\"width:100%;border-collapse:collapse;margin:12px 0;font-size:14px;\"><tr><th style=\"background:#f5f5f5;text-align:left;padding:8px 12px;font-weight:600;font-size:13px;color:#555;border:1px solid #e5e7eb;\">页码</th><th style=\"background:#f5f5f5;text-align:left;padding:8px 12px;font-weight:600;font-size:13px;color:#555;border:1px solid #e5e7eb;\">OFFSET 值</th><th style=\"background:#f5f5f5;text-align:left;padding:8px 12px;font-weight:600;font-size:13px;color:#555;border:1px solid #e5e7eb;\">扫描行数</th><th style=\"background:#f5f5f5;text-align:left;padding:8px 12px;font-weight:600;font-size:13px;color:#555;border:1px solid #e5e7eb;\">相对耗时（100万行表）</th></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">1</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">0</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">20</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">~1ms</td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">100</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">1,980</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">2,000</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">~5ms</td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">1,000</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">19,980</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">20,000</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">~40ms</td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">10,000</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">199,980</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">200,000</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">~350ms</td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">50,000</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">999,980</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">1,000,000</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">~1.8s</td></tr></table></section>\n<section><h2 style=\"font-size:20px;font-weight:700;color:#1a1a2e;border-bottom:2px solid #1e6fff;padding-bottom:6px;margin:36px 0 16px;\">10.2 Keyset 分页原理</h2></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">Keyset 分页（也称 Seek Method 或 Cursor-based Pagination）利用上一页最后一条记录的排序键值作为下一页查询的\n<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">WHERE</code> 条件，从而绕过 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">OFFSET</code> 的行扫描开销。</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">Keyset 分页核心算法</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">SELECT</p></section><p style=\"text-align:center;font-size:16px;color:#bbb;margin:0;line-height:1.2;\">↓</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">ORDER</p></section><p style=\"text-align:center;font-size:16px;color:#bbb;margin:0;line-height:1.2;\">↓</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">WHERE</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">客户端请求第 1 页\"] --> B[\"SELECT ... ORDER BY created_at DESC, id DESC LIMIT 20</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">SELECT ... ORDER BY created_at DESC, id DESC LIMIT 20</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">返回 20 行 + 提取最后一行的 Keyset</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #e6a817;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">◇ 用户点击下一页?</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">SELECT ... WHERE (created_at, id) < (lastDate, lastId) ORDER BY created_at DESC, id DESC LIMIT 20</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">返回 20 行 + 提取新的 Keyset</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">结束</p></section></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">这个方法的数学本质是：给定排序列 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">(c1, c2, ... cn)</code> 和上一页最后行的值 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">(v1, v2, ... vn)</code>，\n下一页的条件等价于字典序比较：</p></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">WHERE (c1, c2, ..., cn) &lt; (v1, v2, ..., vn)   -- DESC 排序<br/>WHERE (c1, c2, ..., cn) &gt; (v1, v2, ..., vn)   -- ASC 排序</p></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">由于查询条件直接命中索引的 B-Tree 叶节点，无论请求第几页，数据库只需一次索引查找 + 顺序读取 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">LIMIT</code> 行，\n复杂度为 <strong style=\"color:#1a1a2e;font-weight:700;\">O(log n + pageSize)</strong>，约等于 <strong style=\"color:#1a1a2e;font-weight:700;\">O(1)</strong>。</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">Offset O(n) vs Keyset O(1) 性能对比</p><section style=\"border:2px solid #1e6fff55;border-radius:10px;padding:14px 12px;margin:6px 0;background:#f5f5f5;\"><p style=\"font-size:12px;font-weight:700;color:#1e6fff;margin:0 0 8px;\">Offset 分页 — O(n)</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">第 1 页: 1ms\"] --> O2[\"第 100 页: 5ms</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">第 100 页: 5ms</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">第 1000 页: 40ms</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">第 10000 页: 350ms</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">第 50000 页: 1800ms ⚠</p></section></section><section style=\"border:2px solid #1e6fff55;border-radius:10px;padding:14px 12px;margin:6px 0;background:#f5f5f5;\"><p style=\"font-size:12px;font-weight:700;color:#1e6fff;margin:0 0 8px;\">Keyset 分页 — O(1)</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">第 1 页: 1ms\"] --> K2[\"第 100 页: 1ms</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">第 100 页: 1ms</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">第 1000 页: 1ms</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">第 10000 页: 1ms</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">第 50000 页: 1ms ✅</p></section></section></section>\n<section style=\"background:#f5f5f5;border:1px solid #1e6fff44;border-radius:8px;padding:14px 16px;margin:14px 0 20px;font-size:14px;line-height:1.8;color:#2b2b2b;\">\n<strong style=\"color:#1a1a2e;font-weight:700;\">💡 索引利用：</strong>Keyset 分页的高性能前提是排序列上存在合适的复合索引。\n  例如 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">ORDER BY created_at DESC, id DESC</code> 需要 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">INDEX(created_at DESC, id DESC)</code>，\n  这样数据库可以直接从 B-Tree 的目标位置开始顺序扫描。\n</section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">B-Tree 索引中 Offset vs Keyset 的扫描路径</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">B</p></section><p style=\"text-align:center;font-size:16px;color:#bbb;margin:0;line-height:1.2;\">↓</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">Tree</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">1</p></section><p style=\"text-align:center;font-size:16px;color:#bbb;margin:0;line-height:1.2;\">↓</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">100</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">101</p></section><p style=\"text-align:center;font-size:16px;color:#bbb;margin:0;line-height:1.2;\">↓</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">200</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">201</p></section><p style=\"text-align:center;font-size:16px;color:#bbb;margin:0;line-height:1.2;\">↓</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">300</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">301</p></section><p style=\"text-align:center;font-size:16px;color:#bbb;margin:0;line-height:1.2;\">↓</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">400</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">401</p></section><p style=\"text-align:center;font-size:16px;color:#bbb;margin:0;line-height:1.2;\">↓</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">500</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">501</p></section><p style=\"text-align:center;font-size:16px;color:#bbb;margin:0;line-height:1.2;\">↓</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">600</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">B-Tree 根节点\"] --> N1[\"内部节点 A</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">内部节点 A</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">内部节点 B</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">内部节点 C</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">叶子 1..100</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">叶子 101..200</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">叶子 201..300</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">叶子 301..400</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">叶子 401..500</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">叶子 501..600</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">Offset: 从叶子 1 开始<br/>逐行扫描到目标位置</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">Keyset: 直接定位<br/>目标叶子节点</p></section></section>\n<section><h2 style=\"font-size:20px;font-weight:700;color:#1a1a2e;border-bottom:2px solid #1e6fff;padding-bottom:6px;margin:36px 0 16px;\">10.3 Blaze-Persistence PaginatedCriteriaBuilder</h2></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">Blaze-Persistence 通过 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">PaginatedCriteriaBuilder</code> 统一了 Offset 和 Keyset 两种分页模式。\n调用 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">page(firstResult, maxResults)</code> 使用 Offset 模式，调用 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">page(keysetPage, firstResult, maxResults)</code>\n则启用 Keyset 模式。两种模式返回相同的 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">PagedList<T></code> 结果。</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">PaginatedCriteriaBuilder API 全景</p><section style=\"margin:4px 0;padding:6px 12px;border:1px solid #1e6fff;border-radius:5px;background:#f5f5f5;\"><p style=\"margin:0;font-size:12px;font-weight:700;color:#1e6fff;\">KeysetPage</p><p style=\"margin:2px 0 0;font-size:10px;color:#888;font-family:Consolas,monospace;\">getFirstResult · getMaxResults · getLowest · getHighest · getKeysets</p></section></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">Offset 分页示例</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">CriteriaBuilder&lt;Cat&gt; cb = cbf.create(em, Cat.class)<br/>    .orderByAsc(\"name\")<br/>    .orderByAsc(\"id\");<br/><br/><span style=\"color:#6c7086;font-style:italic;\">// 第 3 页，每页 20 条（firstResult = 40）</span><br/>PagedList&lt;Cat&gt; page3 = cb.page(40, 20).getResultList();<br/><br/>long total  = page3.getTotalSize();   <span style=\"color:#6c7086;font-style:italic;\">// 总行数</span><br/>int  pages  = page3.getTotalPages();  <span style=\"color:#6c7086;font-style:italic;\">// 总页数</span><br/><span style=\"color:#6c7086;font-style:italic;\">// page3 包含 cat 实体列表</span></p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">Keyset 分页示例</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\"><span style=\"color:#6c7086;font-style:italic;\">// 第 1 页：普通 Offset 调用获取初始 KeysetPage</span><br/>PagedList&lt;Cat&gt; page1 = cb.page(0, 20).getResultList();<br/>KeysetPage keyset = page1.getKeysetPage();<br/><br/><span style=\"color:#6c7086;font-style:italic;\">// 第 2 页：传入上一页的 KeysetPage</span><br/>PagedList&lt;Cat&gt; page2 = cb.page(keyset, 20, 20).getResultList();<br/><span style=\"color:#6c7086;font-style:italic;\">// 数据库生成 WHERE (name, id) &gt; (lastName, lastId) 而非 OFFSET 20</span></p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">Offset vs Keyset 分页 — 完整请求流程</p><table style=\"width:100%;border-collapse:collapse;margin:0 0 8px;\"><tr><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">客户端</th><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">Blaze-Persistence</th><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">数据库</th></tr></table><p style=\"text-align:center;font-size:11px;color:#888;background:#f5f5f5;border:1px solid #e6a81744;border-radius:4px;padding:4px 8px;margin:3px auto;max-width:80%;\">📌 Offset 模式</p><p style=\"text-align:center;font-size:11px;color:#888;background:#f5f5f5;border:1px solid #e6a81744;border-radius:4px;padding:4px 8px;margin:3px auto;max-width:80%;\">📌 Keyset 模式</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #1e6fff44;border-radius:8px;padding:14px 16px;margin:14px 0 20px;font-size:14px;line-height:1.8;color:#2b2b2b;\">\n<strong style=\"color:#1a1a2e;font-weight:700;\">💡 无缝切换：</strong>第一次请求必须使用 Offset 模式（因为还没有 KeysetPage），\n  后续请求传入 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">KeysetPage</code> 即可自动切换到 Keyset 模式。API 返回的 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">PagedList</code> 始终包含\n  <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">KeysetPage</code>，方便客户端持续翻页。\n</section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">KeysetPage 的序列化</h3></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">在 REST API 场景中，<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">KeysetPage</code> 需要在客户端和服务端之间传递。Blaze-Persistence 提供了\n<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">KeysetPageable</code> 与 Spring Data 集成的序列化方案。也可以手动将 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">KeysetPage</code> 序列化为 JSON：</p></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\"><span style=\"color:#6c7086;font-style:italic;\">// 序列化：将 KeysetPage 转为可传输的 DTO</span><br/>KeysetPage kp = pagedList.getKeysetPage();<br/>Map&lt;String, Object&gt; dto = Map.of(<br/>    \"firstResult\", kp.getFirstResult(),<br/>    \"maxResults\",  kp.getMaxResults(),<br/>    \"lowest\",      kp.getLowest().getTuple(),   <span style=\"color:#6c7086;font-style:italic;\">// Object[]</span><br/>    \"highest\",     kp.getHighest().getTuple()    <span style=\"color:#6c7086;font-style:italic;\">// Object[]</span><br/>);<br/><span style=\"color:#6c7086;font-style:italic;\">// 转为 JSON 发送给客户端</span><br/><br/><span style=\"color:#6c7086;font-style:italic;\">// 反序列化：从客户端接收后重建</span><br/>KeysetPage restored = new DefaultKeysetPage(<br/>    firstResult, maxResults,<br/>    new DefaultKeyset(lowestTuple),<br/>    new DefaultKeyset(highestTuple),<br/>    Collections.emptyList()<br/>);</p></section>\n<section><h2 style=\"font-size:20px;font-weight:700;color:#1a1a2e;border-bottom:2px solid #1e6fff;padding-bottom:6px;margin:36px 0 16px;\">10.4 COUNT 查询优化</h2></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">默认情况下，<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">PaginatedCriteriaBuilder</code> 会自动生成一条 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">COUNT(*)</code> 查询以计算总行数。\n在大表上，这条 COUNT 查询可能比分页查询本身更慢。Blaze-Persistence 提供了多种优化手段。</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">COUNT 查询生成与优化决策树</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">PaginatedCriteriaBuilder 执行</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #e6a817;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">◇ withCountQuery?</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #e6a817;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">◇ 有自定义 COUNT?</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">跳过 COUNT<br/>totalSize = -1</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">使用自定义 COUNT 查询</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">自动生成 COUNT 查询</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #e6a817;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">◇ 查询包含 GROUP BY?</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">包装为 SELECT COUNT(*)<br/>FROM (原查询) sub</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">直接 SELECT COUNT(*)<br/>FROM entity WHERE ...</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">执行 COUNT + 分页</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">仅执行分页查询</p></section></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">关闭 COUNT 查询</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">PagedList&lt;Cat&gt; page = cb.page(0, 20)<br/>    .withCountQuery(false)     <span style=\"color:#6c7086;font-style:italic;\">// 不执行 COUNT</span><br/>    .getResultList();<br/><br/><span style=\"color:#6c7086;font-style:italic;\">// page.getTotalSize() == -1</span><br/><span style=\"color:#6c7086;font-style:italic;\">// page.getTotalPages() == -1</span></p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">自定义 COUNT 查询</h3></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">当自动生成的 COUNT 查询性能不理想时，可以提供一个优化过的自定义 COUNT：</p></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">PagedList&lt;Cat&gt; page = cb.page(0, 20)<br/>    .withCountQuery(<br/>        cbf.create(em, Long.class)<br/>           .from(Cat.class, \"c\")<br/>           .select(\"COUNT(c.id)\")<br/>           .where(\"c.age\").gt(3)<br/>    )<br/>    .getResultList();</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">withExtractAllKeysets 批量预计算</p><section style=\"border:2px solid #1e6fff55;border-radius:10px;padding:14px 12px;margin:6px 0;background:#f5f5f5;\"><p style=\"font-size:12px;font-weight:700;color:#1e6fff;margin:0 0 8px;\">默认模式</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">提取第一行 Keyset\"] --> D2[\"提取最后一行 Keyset</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">提取最后一行 Keyset</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">其他行无 Keyset 信息</p></section></section><section style=\"border:2px solid #1e6fff55;border-radius:10px;padding:14px 12px;margin:6px 0;background:#f5f5f5;\"><p style=\"font-size:12px;font-weight:700;color:#1e6fff;margin:0 0 8px;\">withExtractAllKeysets(true)</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">提取第 1 行 Keyset\"] --> E2[\"提取第 2 行 Keyset</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">提取第 2 行 Keyset</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">提取第 3 行 Keyset</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">...</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">提取第 20 行 Keyset</p></section></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">只能顺序翻页</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">可跳转到任意行位置</p></section></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">PagedList&lt;Cat&gt; page = cb.page(0, 20)<br/>    .withExtractAllKeysets(true)   <span style=\"color:#6c7086;font-style:italic;\">// 为每一行计算 Keyset</span><br/>    .getResultList();<br/><br/>KeysetPage ks = page.getKeysetPage();<br/>List&lt;Keyset&gt; allKeysets = ks.getKeysets();  <span style=\"color:#6c7086;font-style:italic;\">// 20 个 Keyset</span><br/><span style=\"color:#6c7086;font-style:italic;\">// 可实现\"跳转到第 N 行\"的精确定位</span></p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e6a81744;border-radius:8px;padding:14px 16px;margin:14px 0 20px;font-size:14px;line-height:1.8;color:#2b2b2b;\">\n<strong style=\"color:#1a1a2e;font-weight:700;\">📊 性能权衡：</strong><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">withExtractAllKeysets(true)</code> 会在 SELECT 列表中增加额外列以提取所有行的排序键值，\n  这会增加约 10-15% 的查询开销。仅在需要精确跳页时启用。\n</section>\n<section><h2 style=\"font-size:20px;font-weight:700;color:#1a1a2e;border-bottom:2px solid #1e6fff;padding-bottom:6px;margin:36px 0 16px;\">10.5 Entity View 分页</h2></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">Blaze-Persistence 最大的优势之一就是将 Entity View 投影与分页 API 无缝结合。\n通过 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">EntityViewSetting</code> 包装分页参数，可以直接返回 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">PagedList<ViewClass></code>。</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">Entity View + Pagination 管线全景</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">EntityViewSetting</p></section><p style=\"text-align:center;font-size:16px;color:#bbb;margin:0;line-height:1.2;\">↓</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">create</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">setting</p></section><p style=\"text-align:center;font-size:16px;color:#bbb;margin:0;line-height:1.2;\">↓</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">withKeysetPage</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">evm</p></section><p style=\"text-align:center;font-size:16px;color:#bbb;margin:0;line-height:1.2;\">↓</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">applySetting</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">EntityViewSetting.create(CatView.class)\"] --> B[\"setting.withPagination(firstResult, maxResults)</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">setting.withPagination(firstResult, maxResults)</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">setting.withKeysetPage(keysetPage)</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">evm.applySetting(setting, cb)</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">PaginatedCriteriaBuilder<CatView></p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">自动生成优化 SELECT<br/>仅投影 View 需要的列</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">自动生成 COUNT 查询</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">自动提取 Keyset</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">PagedList<CatView></p></section></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">完整示例</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\"><span style=\"color:#6c7086;font-style:italic;\">// 1. 定义 Entity View</span><br/>@EntityView(Cat.class)<br/>public interface CatView {<br/>    @IdMapping Long getId();<br/>    String getName();<br/>    @Mapping(\"age\") Integer getAge();<br/>    @Mapping(\"owner.name\") String getOwnerName();<br/>}<br/><br/><span style=\"color:#6c7086;font-style:italic;\">// 2. 构建基础查询</span><br/>CriteriaBuilder&lt;Cat&gt; cb = cbf.create(em, Cat.class)<br/>    .where(\"age\").gt(1)<br/>    .orderByAsc(\"name\")<br/>    .orderByAsc(\"id\");<br/><br/><span style=\"color:#6c7086;font-style:italic;\">// 3. 创建 EntityViewSetting 并配置分页</span><br/>EntityViewSetting&lt;CatView, PaginatedCriteriaBuilder&lt;CatView&gt;&gt; setting =<br/>    EntityViewSetting.create(CatView.class, 0, 20);<br/><br/><span style=\"color:#6c7086;font-style:italic;\">// 4. 应用 Setting，获取分页结果</span><br/>PaginatedCriteriaBuilder&lt;CatView&gt; pcb = evm.applySetting(setting, cb);<br/>PagedList&lt;CatView&gt; page = pcb.getResultList();<br/><br/><span style=\"color:#6c7086;font-style:italic;\">// 5. 使用结果</span><br/>page.forEach(v -&gt; System.out.println(v.getName()));<br/>long total = page.getTotalSize();<br/>KeysetPage keyset = page.getKeysetPage();  <span style=\"color:#6c7086;font-style:italic;\">// 传给下一页请求</span></p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">Entity View 分页的 SQL 生成对比</p><table style=\"width:100%;border-collapse:collapse;margin:0 0 8px;\"><tr><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">应用代码</th><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">EntityViewManager</th><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">PaginatedCriteriaBuilder</th><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">数据库</th></tr></table></section>\n<section style=\"background:#f5f5f5;border:1px solid #1e6fff44;border-radius:8px;padding:14px 16px;margin:14px 0 20px;font-size:14px;line-height:1.8;color:#2b2b2b;\">\n<strong style=\"color:#1a1a2e;font-weight:700;\">💡 SELECT 优化：</strong>Entity View 分页不会 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">SELECT *</code>。\n  Blaze-Persistence 根据 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">CatView</code> 的 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">@Mapping</code> 注解，自动生成仅包含需要列的 SELECT，\n  减少 I/O 和反序列化开销。\n</section>\n<section><h2 style=\"font-size:20px;font-weight:700;color:#1a1a2e;border-bottom:2px solid #1e6fff;padding-bottom:6px;margin:36px 0 16px;\">10.6 多列 Keyset</h2></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">在实际业务中，单列排序（如仅按 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">id</code>）往往不够用。常见场景是按\"创建时间 + ID\"复合排序，\n或按\"状态 + 优先级 + ID\"多列排序。Keyset 分页需要将所有排序列作为 Keyset 的组成部分。</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">多列 Keyset 的字典序比较逻辑</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">created_at</p></section><p style=\"text-align:center;font-size:16px;color:#bbb;margin:0;line-height:1.2;\">↓</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">lastDate</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">WHERE 条件生成<br/>ORDER BY created_at DESC, id ASC</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #e6a817;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">◇ created_at < lastDate ?</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">✅ 匹配 — 取这一行</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #e6a817;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">◇ created_at = lastDate ?</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #e6a817;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">◇ id > lastId ?</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">❌ 不匹配 — 跳过</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">✅ 匹配 — 取这一行</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">❌ 不匹配 — 跳过</p></section></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">Blaze-Persistence 自动将多列排序转换为等价的 SQL 条件：</p></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">-- ORDER BY created_at DESC, id ASC 的 Keyset 条件展开<br/>WHERE (<br/>    created_at &lt; ?lastDate<br/>    OR (created_at = ?lastDate AND id &gt; ?lastId)<br/>)</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">三列排序的 Keyset</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">CriteriaBuilder&lt;Order&gt; cb = cbf.create(em, Order.class)<br/>    .orderByDesc(\"priority\")<br/>    .orderByDesc(\"createdAt\")<br/>    .orderByAsc(\"id\");  <span style=\"color:#6c7086;font-style:italic;\">// 确保确定性排序</span><br/><br/><span style=\"color:#6c7086;font-style:italic;\">// 生成的 Keyset WHERE 条件:</span><br/><span style=\"color:#6c7086;font-style:italic;\">// WHERE (</span><br/><span style=\"color:#6c7086;font-style:italic;\">//     priority &lt; ?lastPriority</span><br/><span style=\"color:#6c7086;font-style:italic;\">//     OR (priority = ?lastPriority AND createdAt &lt; ?lastDate)</span><br/><span style=\"color:#6c7086;font-style:italic;\">//     OR (priority = ?lastPriority AND createdAt = ?lastDate AND id &gt; ?lastId)</span><br/><span style=\"color:#6c7086;font-style:italic;\">// )</span></p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">三列 Keyset 的条件展开树</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">priority</p></section><p style=\"text-align:center;font-size:16px;color:#bbb;margin:0;line-height:1.2;\">↓</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">P₀</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">createdAt</p></section><p style=\"text-align:center;font-size:16px;color:#bbb;margin:0;line-height:1.2;\">↓</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">D₀</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">(priority, createdAt, id)<br/>与 (P₀, D₀, I₀) 比较</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #e6a817;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">◇ priority < P₀ ?</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">✅ 取此行</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #e6a817;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">◇ priority = P₀ ?</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">❌ 跳过<br/>priority > P₀</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #e6a817;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">◇ createdAt < D₀ ?</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">✅ 取此行</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #e6a817;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">◇ createdAt = D₀ ?</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">❌ 跳过<br/>createdAt > D₀</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #e6a817;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">◇ id > I₀ ?</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">✅ 取此行</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">❌ 跳过<br/>id ≤ I₀</p></section></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">NULL 值处理</h3></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">当排序列可能为 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">NULL</code> 时，Keyset 比较需要额外处理 NULL 语义。Blaze-Persistence 根据\n<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">NULLS FIRST</code> / <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">NULLS LAST</code> 配置自动生成正确的 IS NULL 条件：</p></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">CriteriaBuilder&lt;Task&gt; cb = cbf.create(em, Task.class)<br/>    .orderByDesc(\"dueDate\")  <span style=\"color:#6c7086;font-style:italic;\">// dueDate 可能为 NULL</span><br/>    .orderByAsc(\"id\");<br/><br/><span style=\"color:#6c7086;font-style:italic;\">// 如果 lastDueDate 为 NULL，Blaze-Persistence 自动处理:</span><br/><span style=\"color:#6c7086;font-style:italic;\">// WHERE (</span><br/><span style=\"color:#6c7086;font-style:italic;\">//     dueDate IS NOT NULL</span><br/><span style=\"color:#6c7086;font-style:italic;\">//     OR (dueDate IS NULL AND id &gt; ?lastId)</span><br/><span style=\"color:#6c7086;font-style:italic;\">// )</span></p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e0525244;border-radius:8px;padding:14px 16px;margin:14px 0 20px;font-size:14px;line-height:1.8;color:#2b2b2b;\">\n<strong style=\"color:#1a1a2e;font-weight:700;\">⚠ NULL 排序陷阱：</strong>不同数据库对 NULL 的默认排序位置不同：\n  PostgreSQL 默认 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">NULLS LAST</code>（ASC 时），Oracle 默认 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">NULLS LAST</code>（DESC 时）。\n  务必显式指定 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">NULLS FIRST</code> 或 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">NULLS LAST</code> 以保证跨数据库一致性。\n</section>\n<section><h2 style=\"font-size:20px;font-weight:700;color:#1a1a2e;border-bottom:2px solid #1e6fff;padding-bottom:6px;margin:36px 0 16px;\">10.7 陷阱与限制</h2></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">Keyset 分页虽然性能优异，但并非万能。理解其限制才能在合适的场景中选择合适的分页策略。</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">Keyset 分页的适用场景决策树</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #e6a817;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">◇ 需要跳转到任意页码?</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #e6a817;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">◇ 数据量大<br/>> 10 万行?</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">✅ 使用 Keyset 分页</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">使用混合策略<br/>Keyset + 页码估算</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">✅ 使用 Offset 分页</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #e6a817;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">◇ 排序列有索引?</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">最佳性能 O(1)</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">先创建复合索引</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #e6a817;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">◇ 包含集合 JOIN?</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">⚠ 可能产生笛卡尔积<br/>需要子查询分页</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">正常使用</p></section></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">限制一览表</h3></section>\n<section><table style=\"width:100%;border-collapse:collapse;margin:12px 0;font-size:14px;\"><tr><th style=\"background:#f5f5f5;text-align:left;padding:8px 12px;font-weight:600;font-size:13px;color:#555;border:1px solid #e5e7eb;\">限制</th><th style=\"background:#f5f5f5;text-align:left;padding:8px 12px;font-weight:600;font-size:13px;color:#555;border:1px solid #e5e7eb;\">原因</th><th style=\"background:#f5f5f5;text-align:left;padding:8px 12px;font-weight:600;font-size:13px;color:#555;border:1px solid #e5e7eb;\">应对策略</th></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">不能跳转到任意页</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">Keyset 依赖上一页的排序键值，无法凭空计算第 N 页的 Keyset</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">结合 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">withExtractAllKeysets</code> 或使用 Offset 兜底</td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">必须有确定性排序</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">排序必须唯一确定每一行的位置，否则 Keyset 会跳过或重复行</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">始终在排序末尾追加主键列（如 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">id</code>）</td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">排序列变更后 Keyset 失效</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">如果排序列的值被修改（如 status 变化），已发出的 Keyset 指向的位置可能不再正确</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">使用不可变排序列（如 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">createdAt</code>）或在变更后重新获取第 1 页</td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">集合 JOIN 导致行膨胀</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">JOIN FETCH</code> 一对多关联会让每行变成多行，<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">LIMIT</code> 计数错误</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">Blaze-Persistence 自动使用 ID 子查询分页策略</td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">COUNT 在超大表上仍然慢</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">即使 Keyset 分页本身很快，<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">COUNT(*)</code> 仍需全表扫描</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">使用 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">withCountQuery(false)</code> 或维护近似计数器</td></tr></table></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">集合 JOIN 分页 — ID 子查询策略</p><table style=\"width:100%;border-collapse:collapse;margin:0 0 8px;\"><tr><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">Blaze-Persistence</th><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">数据库</th></tr></table><p style=\"text-align:center;font-size:11px;color:#888;background:#f5f5f5;border:1px solid #e6a81744;border-radius:4px;padding:4px 8px;margin:3px auto;max-width:80%;\">📌 检测到查询包含集合 JOIN</p><p style=\"text-align:center;font-size:11px;color:#888;background:#f5f5f5;border:1px solid #e6a81744;border-radius:4px;padding:4px 8px;margin:3px auto;max-width:80%;\">📌 按 ID 分组，组装为 20 个实体</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #1e6fff44;border-radius:8px;padding:14px 16px;margin:14px 0 20px;font-size:14px;line-height:1.8;color:#2b2b2b;\">\n<strong style=\"color:#1a1a2e;font-weight:700;\">💡 ID 子查询策略：</strong>当分页查询包含集合 JOIN 时，Blaze-Persistence 自动拆分为两步：\n  先用子查询按 LIMIT 取出主键列表，再用 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">IN</code> 条件获取完整数据。这避免了笛卡尔积导致的\n  LIMIT 计数错误，是 Blaze-Persistence 相比原生 JPA 的重要优势。\n</section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">REST API 中的 Keyset 序列化最佳实践</h3></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">REST API Keyset 分页流程</p><table style=\"width:100%;border-collapse:collapse;margin:0 0 8px;\"><tr><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">前端</th><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">REST API</th><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">Blaze-Persistence</th><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">数据库</th></tr></table></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\"><span style=\"color:#6c7086;font-style:italic;\">// REST Controller 示例</span><br/>@GetMapping(\"/cats\")<br/>public ResponseEntity&lt;PagedResponse&lt;CatView&gt;&gt; listCats(<br/>        @RequestParam(defaultValue = \"0\") int offset,<br/>        @RequestParam(defaultValue = \"20\") int size,<br/>        @RequestParam(required = false) String afterKeyset) {<br/><br/>    CriteriaBuilder&lt;Cat&gt; cb = cbf.create(em, Cat.class)<br/>        .orderByAsc(\"name\")<br/>        .orderByAsc(\"id\");<br/><br/>    EntityViewSetting&lt;CatView, PaginatedCriteriaBuilder&lt;CatView&gt;&gt; setting;<br/><br/>    if (afterKeyset != null) {<br/>        KeysetPage keyset = deserializeKeyset(afterKeyset);<br/>        setting = EntityViewSetting.create(CatView.class, offset, size);<br/>        setting.withKeysetPage(keyset);<br/>    } else {<br/>        setting = EntityViewSetting.create(CatView.class, offset, size);<br/>    }<br/><br/>    PagedList&lt;CatView&gt; result = evm.applySetting(setting, cb).getResultList();<br/><br/>    return ResponseEntity.ok(new PagedResponse&lt;&gt;(<br/>        result,<br/>        result.getTotalSize(),<br/>        serializeKeyset(result.getKeysetPage())<br/>    ));<br/>}</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #1e6fff22;border-radius:10px;padding:20px 22px;margin:36px 0 16px;\"><p style=\"font-size:18px;font-weight:700;color:#1e6fff;margin:0 0 12px;\">📋 本章小结</p><ul style=\"margin:8px 0 12px 20px;color:#2b2b2b;\"><li style=\"margin-bottom:5px;font-size:14px;\"><strong style=\"color:#1a1a2e;font-weight:700;\">Offset 分页</strong>的 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">O(n)</code> 扫描复杂度在大表上不可接受，且并发写入时存在丢行/重复行风险</li><li style=\"margin-bottom:5px;font-size:14px;\"><strong style=\"color:#1a1a2e;font-weight:700;\">Keyset 分页</strong>通过 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">WHERE (cols) > (lastVals)</code> 条件实现 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">O(1)</code> 翻页，前提是排序列有合适索引</li><li style=\"margin-bottom:5px;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">PaginatedCriteriaBuilder</code> 统一了两种分页模式：<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">page(offset, size)</code> 与 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">page(keyset, offset, size)</code></li><li style=\"margin-bottom:5px;font-size:14px;\">COUNT 查询可通过 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">withCountQuery(false)</code> 关闭或提供自定义 COUNT 查询优化性能</li><li style=\"margin-bottom:5px;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">withExtractAllKeysets(true)</code> 为每行提取 Keyset，支持更灵活的跳页策略</li><li style=\"margin-bottom:5px;font-size:14px;\">Entity View 与分页 API 无缝结合，返回 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">PagedList<ViewClass></code>，自动优化 SELECT 列</li><li style=\"margin-bottom:5px;font-size:14px;\">多列 Keyset 自动展开为字典序比较条件，NULL 值根据 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">NULLS FIRST/LAST</code> 配置处理</li><li style=\"margin-bottom:5px;font-size:14px;\">集合 JOIN 场景下 Blaze-Persistence 自动采用 ID 子查询策略避免笛卡尔积</li></ul><p style=\"font-size:13px;color:#888;margin-top:10px;padding-top:10px;border-top:1px solid #e5e7eb;\">\n    下一章 <span style=\"color:#1e6fff;\">第 11 章 · 批量 DML</span> 将讲解如何使用 CriteriaBuilder 构建 UPDATE / DELETE / INSERT-SELECT 批量操作，\n    以及如何处理 JPA 缓存一致性问题。\n  </p></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">© 2026 图解 Blaze-Persistence · 第 10 章 · 分页</p></section>";
  await page.waitForSelector('.ProseMirror', { timeout: 15000 });
  if (title) {
    var ti = page.locator('textarea[placeholder="请在这里输入标题"]');
    await ti.fill(title);
    await page.waitForTimeout(300);
  }
  await page.evaluate((h) => {
    var pm = document.querySelector('.ProseMirror');
    pm.focus();
    var dt = new DataTransfer();
    dt.setData('text/html', h);
    var ev = new ClipboardEvent('paste', {bubbles:true, cancelable:true, clipboardData:dt});
    pm.dispatchEvent(ev);
  }, html);
  await page.waitForTimeout(1500);
  var enableBtns = page.locator('label:has-text("开启")');
  var cnt = await enableBtns.count();
  for (var i = 0; i < cnt; i++) {
    try {
      var b = enableBtns.nth(i);
      if (await b.isVisible({ timeout: 500 })) await b.click({ timeout: 1000 });
    } catch(e) {}
  }
  await page.waitForTimeout(500);
  var saveBtn = page.getByRole('button', { name: '保存为草稿' });
  await saveBtn.click();
  await page.waitForTimeout(2000);
  return title + ' -> saved';
}